import{_ as e,o as i,c as l,aQ as t}from"./chunks/framework.cDvftfeu.js";const u=JSON.parse('{"title":"図書館","description":"Hamで図書館の座席を予約する方法。","frontmatter":{"description":"Hamで図書館の座席を予約する方法。"},"headers":[],"relativePath":"ja/handbook/library.md","filePath":"ja/handbook/library.md","lastUpdated":1777525243000}'),r={name:"ja/handbook/library.md"};function o(h,a,d,n,p,s){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="図書館" tabindex="-1">図書館 <a class="header-anchor" href="#図書館" aria-label="Permalink to &quot;図書館&quot;">​</a></h1><p>Hamを使って図書館の座席予約を簡単に行えます。</p><h2 id="準備" tabindex="-1">準備 <a class="header-anchor" href="#準備" aria-label="Permalink to &quot;準備&quot;">​</a></h2><p>図書館機能を使う前に以下が必要です：</p><ul><li>情報ポータルアカウント</li></ul><h3 id="情報ポータルアカウントの準備" tabindex="-1">情報ポータルアカウントの準備 <a class="header-anchor" href="#情報ポータルアカウントの準備" aria-label="Permalink to &quot;情報ポータルアカウントの準備&quot;">​</a></h3><p>図書館座席予約システムは情報ポータル（CAS）の統一認証でログインします。Hamで情報ポータルのアカウントとパスワードを設定してください。情報ポータルの認証情報を忘れた場合は、情報ポータルのウェブサイトでリセットしてください。</p><h2 id="座席マップ予約" tabindex="-1">座席マップ予約 <a class="header-anchor" href="#座席マップ予約" aria-label="Permalink to &quot;座席マップ予約&quot;">​</a></h2><p>図書館・部屋・座席ごとの空き状況を見て直接予約できます。</p><p>座席マップ予約に向くケース：</p><ul><li>今日は図書館に行きたいが予約がない</li><li>部屋や座席にこだわりがない</li></ul><p>座席マップ予約は図書館機能の最初のタブ（旧バージョンでは「予約」）です。</p><div class="tip custom-block"><p class="custom-block-title">注意</p><p>座席を選択した後に他の学生が予約した場合、Hamは近くの座席を自動で選びません。</p></div><h2 id="クイック予約" tabindex="-1">クイック予約 <a class="header-anchor" href="#クイック予約" aria-label="Permalink to &quot;クイック予約&quot;">​</a></h2><p>お気に入りの座席を保存して、すぐに予約できます。</p><p>クイック予約が便利なケース：</p><ul><li>図書館によく行き、固定の席がある</li><li>自動化予約を使いたい</li><li>すぐに図書館へ行きたいが特定の部屋に座りたい</li></ul><p>Hamで予約したことがある、または「優先座席」を設定していると、図書館トップにクイック予約タブが表示されます。座席や時間をタップして一時的に変更することも可能です。</p><div class="tip custom-block"><p class="custom-block-title">注意</p><p>クイック予約は「優先座席」の設定にできる限り合わせます。予約に失敗した場合、Hamが近くの席をすぐに選びます。</p></div><h2 id="優先座席" tabindex="-1">優先座席 <a class="header-anchor" href="#優先座席" aria-label="Permalink to &quot;優先座席&quot;">​</a></h2><p>クイック予約で使われるデフォルトの座席です。</p><p>予約時間・座席・好みを事前に設定できます。図書館ページを開くたびに、クイック予約がこの設定を使用します。</p><p>優先座席は「図書館設定」で変更できます。</p><h2 id="予約ステータス" tabindex="-1">予約ステータス <a class="header-anchor" href="#予約ステータス" aria-label="Permalink to &quot;予約ステータス&quot;">​</a></h2><p>有効な予約がある場合、図書館ホームとステータスページに表示されます。</p><p>ステータスから予約時間の変更やキャンセルが可能です。</p><p>長時間予約で途中退出が必要な場合（図書館の制限を超えるとき）、退出前に予約時間を変更して戻ってきた際も同じ席に座れるようにできます。</p><p>予約ステータスを取得すると、システムカレンダーに自動で追加され、入館10分前に通知します。（iOS）</p><p>予約ステータスはダイナミックアイランドとLiveActivityに対応し、「予約済み」の状態が通知領域に固定表示され、座席番号、場所、時間などの情報が表示されます。（iOS）</p><h2 id="履歴" tabindex="-1">履歴 <a class="header-anchor" href="#履歴" aria-label="Permalink to &quot;履歴&quot;">​</a></h2><p>図書館の予約履歴を確認できます。</p><h2 id="ウィジェット" tabindex="-1">ウィジェット <a class="header-anchor" href="#ウィジェット" aria-label="Permalink to &quot;ウィジェット&quot;">​</a></h2><p>ウィジェットをホーム画面に置き、予約場所や時間、退席中の時間を確認できます。</p><p>更新間隔を短くしすぎると、図書館側で一時的な利用停止になる可能性があります（目安は15分）。</p><h2 id="その他の図書館設定" tabindex="-1">その他の図書館設定 <a class="header-anchor" href="#その他の図書館設定" aria-label="Permalink to &quot;その他の図書館設定&quot;">​</a></h2><h3 id="基本データの更新" tabindex="-1">基本データの更新 <a class="header-anchor" href="#基本データの更新" aria-label="Permalink to &quot;基本データの更新&quot;">​</a></h3><p>通常、予約ページに入るとHamはローカルの図書館データを使用し、通信を減らして速度を上げます。「図書館」に入るたびに基本データの更新を試みます。</p><ul><li>図書館システムから更新</li></ul><p>このオプションでは端末上で図書館システムにログインし、基本データを取得します。</p><h3 id="リセット" tabindex="-1">リセット <a class="header-anchor" href="#リセット" aria-label="Permalink to &quot;リセット&quot;">​</a></h3><p>図書館機能に異常がある場合は「リセット」を押してください。</p><h3 id="自動化-android" tabindex="-1">自動化（Android） <a class="header-anchor" href="#自動化-android" aria-label="Permalink to &quot;自動化（Android）&quot;">​</a></h3><p>Hamで優先座席を設定し、「マイ」-&gt;「自動化」で自動化を有効にします。設定した時間に優先座席を予約します。システム時刻に基づき、翌日の予約かどうかを判断します。</p><h3 id="自動化-ios" tabindex="-1">自動化（iOS） <a class="header-anchor" href="#自動化-ios" aria-label="Permalink to &quot;自動化（iOS）&quot;">​</a></h3><p>Hamで優先座席を設定し、ショートカットの「オートメーション」で個人用オートメーションを作成します。特定時刻を選び、「操作を追加」-&gt;「App」-&gt;「Ham」-&gt;「図書館クイック予約」を追加し、「実行前に尋ねる」をオフにします。設定した時間に優先座席を予約します。システム時刻に基づき、翌日の予約かどうかを判断します。</p><h3 id="ダイナミックアイランド-liveactivity" tabindex="-1">ダイナミックアイランド / LiveActivity <a class="header-anchor" href="#ダイナミックアイランド-liveactivity" aria-label="Permalink to &quot;ダイナミックアイランド / LiveActivity&quot;">​</a></h3><p>条件を満たす予約は適切なタイミングで表示されます。</p><h2 id="必要な権限" tabindex="-1">必要な権限 <a class="header-anchor" href="#必要な権限" aria-label="Permalink to &quot;必要な権限&quot;">​</a></h2><h3 id="自動化" tabindex="-1">自動化 <a class="header-anchor" href="#自動化" aria-label="Permalink to &quot;自動化&quot;">​</a></h3><ul><li>Android: 自動起動</li></ul><h3 id="ウィジェット-1" tabindex="-1">ウィジェット <a class="header-anchor" href="#ウィジェット-1" aria-label="Permalink to &quot;ウィジェット&quot;">​</a></h3><ul><li>Android: 自動起動</li></ul>',52)])])}const b=e(r,[["render",o]]);export{u as __pageData,b as default};
